            <h4>Oops...! Something went Wrong !</h4>
            <p class="text-muted mx-4 mb-0">Your email Address is invalid</p>
        </div>
        <div class="d-flex gap-2 justify-content-center mt-4 mb-2">
            <button type="button" class="swal2-cancel btn btn-primary w-xs mb-1" aria-label="" style="display: inline-block;" (click)="modal.close('Close click')">Dismiss</button>
        </div>
      </div>
    </div><!-- /.modal-content -->
</ng-template>

