        </div>
      </div>
    </div><!-- /.modal-content -->
</ng-template>

<!-- Email Modal -->
<ng-template #emailContent let-modal>
    <div class="modal-content">
      <div class="modal-header">
          <button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close" id="btn-close" (click)="modal.dismiss('Cross click')"></button>
      </div>
      <div class="text-center">
        <div class="mt-3">
            <div class="avatar-lg mx-auto">
                <div class="avatar-title bg-light text-success display-5 rounded-circle">
                    <i class="ri-mail-send-fill"></i>
                </div>
            </div>
            <div class="mt-4 pt-2 fs-15">
                <h4 class="fs-20 fw-semibold">Verify Your Email</h4>
                <p class="text-muted mb-0 mt-3 fs-13">We have sent you verification email <span class="fw-medium text-body">example@abc.com</span>, <br> Please check it.</p>
            </div>
        </div>
        <div class="d-flex gap-2 justify-content-center mt-4 mb-2">
            <button type="button" class="swal2-confirm btn btn-primary mb-1" aria-label="" (click)="modal.dismiss('Cross click')">Verify Email</button>
        </div>
        <div class="swal2-footer">
            <p class="fs-14 text-muted">Didn't receive an email ? 
                <a href="javascript:void(0);" class="fw-semibold text-decoration-underline">Resend</a>
            </p>
        </div>
      </div>
    </div><!-- /.modal-content -->
</ng-template>

<!-- Notification Modal -->
<ng-template #notificationContent let-modal>
    <div class="modal-content">
      <div class="modal-header">
          <button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Close" id="btn-close" (click)="modal.dismiss('Cross click')"></button>
      </div>
      <div class="modal-body">
          <div class="mt-2 text-center">
            <div class="avatar-lg mx-auto">
                <img src="assets/images/users/avatar-2.jpg" class="rounded-circle img-thumbnail" alt="thumbnail">
            </div>
            <div class="mt-4 pt-2 fs-15 mx-4 mx-sm-5">
                <h4>Welcome Mike Mayer</h4>
                <p class="text-muted mx-4 mb-0">You have 2 Notifications</p>
            </div>
          </div>
          <div class="d-flex gap-2 justify-content-center mt-4 mb-2">
            <button type="button" class="swal2-confirm btn btn-primary mb-1" (click)="modal.close('Close click')">Show Me <i class="ri-arrow-right-line ms-1 align-bottom"></i></button>
          </div>
      </div>
    </div><!-- /.modal-content -->
</ng-template>
